import streamlit as stfrom bridge import MGEPlusBridge# Page setupst.set_page_config(page_title="ANIMA TESTIS • Dual Coherence Demo", layout="centered")st.title("🟢 ANIMA TESTIS")st.subheader("Dual Testimony Coherence")st.caption("Compute alignment between a Founder and an Investor")# Inputsst.markdown("### Founder Testimony")founder_text = st.text_area(    "Founder",    placeholder="Paste founder testimony here...",    height=150)st.markdown("### Investor Testimony")investor_text = st.text_area(    "Investor",    placeholder="Paste investor testimony here...",    height=150)# Initialize bridgebridge = MGEPlusBridge()# Actionif st.button("Compute Shared Coherence"):    result = bridge.run_dual_analysis(founder_text, investor_text)    # Guard for empty input    if result.get("score", 0) == 0 and (not founder_text.strip() or not investor_text.strip()):        st.warning("Please provide both testimonies.")    else:        # Score        st.success(f"Shared Coherence Score: {result['score']}%")        # Gap        st.markdown("### Alignment Gap")        st.info(result["gap"])        # Adjustments        st.markdown("### Founder Adjustment")        st.write(result["founder_adjustment"])        st.markdown("### Investor Adjustment")        st.write(result["investor_adjustment"])        # Improved        st.markdown("### Projected Improved Coherence")        st.metric("Projected", f"{result['improved_score']}%")# Footerst.caption("ANIMA TESTIS • Real MGE+ Geometry • The Quadratic • NACO")